using namespace std;
using namespace std::chrono;
int main() {
  rs::context ctx;
  rs::device *device = ctx.get_device(0);
  device->enable_stream(rs::stream::color, rs::preset::highest_framerate); // 60fps
  device->enable_stream(rs::stream::depth, rs::preset::highest_framerate); // 90fps
  device->start();
  auto last = high_resolution_clock::now();
  while(true) {
    device->wait_for_frames();
    auto now = high_resolution_clock::now();
    auto color = device->get_frame_timestamp(rs::stream::color);
    auto depth = device->get_frame_timestamp(rs::stream::depth);
